import React, { useState } from 'react';
import { useMCPClient } from '../hooks/useMCPClient';

export const FileTree = ({ tree, onSelectFile }) => {
  const { callTool, isConnected } = useMCPClient();
  const [expanded, setExpanded] = useState(new Set());

  const toggleExpand = (path) => {
    const newExpanded = new Set(expanded);
    if (newExpanded.has(path)) {
      newExpanded.delete(path);
    } else {
      newExpanded.add(path);
      // Auto-expand: Fetch children if dir
      if (isConnected && path !== '.') {
        callTool('list_files', { path, recursive: false })
          .then(children => {
            // Update tree logic here (state lift to parent)
            console.log('Children:', children);
          })
          .catch(err => console.error('List files failed:', err));
      }
    }
    setExpanded(newExpanded);
  };

  const renderNode = (node, prefix = '') => {
    if (typeof node === 'string') { // File
      // const isCurrent = currentFile === node;
      return (
        <div 
          className="file-item"
          onClick={() => onSelectFile(node)}
        >
          📄 {node.split('/').pop()}
        </div>
      );
    }

    // Directory
    const isExpanded = expanded.has(node.path);
    const children = node.children || [];
    const hasChildren = children.length > 0;

    return (
      <div className="dir-item">
        <div 
          className="dir-header"
          onClick={() => toggleExpand(node.path)}
        >
          📁 {node.name}
          {hasChildren && <span className={`expand-icon ${isExpanded ? 'expanded' : ''}`}>{isExpanded ? '▼' : '▶'}</span>}
        </div>
        {isExpanded && (
          <div className="children" style={{ paddingLeft: '16px' }}>
            {children.map(child => renderNode(child))}
          </div>
        )}
      </div>
    );
  };

  if (!tree || tree.length === 0) {
    return <div className="empty-tree">No files. Connect MCP to browse workspace.</div>;
  }

  return (
    <div className="file-tree">
      {renderNode({ path: '.', name: 'workspace', children: tree })}
    </div>
  );
};

