const AZURE_CHAT_URL = 'https://mcp-3dx-server-grcrgegehhe6hyhz.westeurope-01.azurewebsites.net/chat';

const MAX_CONTEXT_MESSAGES = 20;

function normalizeConversation(history = []) {
    if (!Array.isArray(history)) {
        return [];
    }

    return history
        .slice(-MAX_CONTEXT_MESSAGES)
        .map((item) => {
            const role = item?.role;
            const content = item?.content;

            if (!['user', 'assistant', 'system'].includes(role) || typeof content !== 'string') {
                return null;
            }

            const trimmedContent = content.trim();
            if (!trimmedContent) {
                return null;
            }

            return {
                role,
                content: trimmedContent,
            };
        })
        .filter(Boolean);
}

export async function callAzureChat(message, conversationHistory = []) {
    const conversation = normalizeConversation(conversationHistory);
    const payload = {
        "message": message,
        "conversation": conversation
    };
    const response = await fetch(AZURE_CHAT_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
    });

    if (!response.ok) {
        throw new Error(`Chat API error: ${response.status}`);
    }

    const data = await response.json();
    console.dir(data);
    return {
        response: data.response,
        mode: data.mode,
        toolCalls: data.endpoint
            ? [{
                name: data.endpoint.action,
                args: { endpoint: data.endpoint }
            }]
            : data.toolCalls?.map(tc => ({
                name: tc,
                args: {}
            })) || []
    };
}