import { useState, useEffect, useCallback, useRef } from 'react';

export const useMCPClient = () => {
  const [isConnected, setIsConnected] = useState(false);
  const [tools, setTools] = useState([]);
  const [serverInfo, setServerInfo] = useState(null);
  const [connectionStatus, setConnectionStatus] = useState('disconnected');
  const wsRef = useRef(null);
  const reconnectTimeoutRef = useRef(null);

  const connect = useCallback(async (serverUrl) => {
    try {
      setConnectionStatus('connecting');

      // Close existing connection
      if (wsRef.current) {
        wsRef.current.close();
      }

      // Create WebSocket connection to MCP server
      wsRef.current = new WebSocket(serverUrl.replace('http', 'ws') + '/mcp');

      wsRef.current.onopen = () => {
        console.log('✅ MCP WebSocket connected');
        setConnectionStatus('connected');
        setIsConnected(true);
      };

      wsRef.current.onmessage = (event) => {
        try {
          const message = JSON.parse(event.data);
          handleMCPMessage(message);
        } catch (e) {
          console.error('MCP message parse error:', e);
        }
      };

      wsRef.current.onclose = (event) => {
        console.log('🔌 MCP disconnected:', event.code, event.reason);
        setIsConnected(false);
        setConnectionStatus('disconnected');
        scheduleReconnect(serverUrl);
      };

      wsRef.current.onerror = (error) => {
        console.error('MCP WebSocket error:', error);
        setConnectionStatus('error');
      };

    } catch (error) {
      console.error('Connection failed:', error);
      setConnectionStatus('error');
    }
  }, []);

  const disconnect = useCallback(() => {
    if (wsRef.current) {
      wsRef.current.close();
    }
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }
    setIsConnected(false);
    setConnectionStatus('disconnected');
    setTools([]);
  }, []);

  const scheduleReconnect = useCallback((serverUrl) => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
    }

    reconnectTimeoutRef.current = setTimeout(() => {
      console.log('🔄 Reconnecting...');
      connect(serverUrl);
    }, 3000);
  }, [connect]);

  const handleMCPMessage = useCallback((message) => {
    if (message.method === 'tools/listChanged') {
      setTools(message.params.tools || []);
      console.log(`📦 ${message.params.tools?.length || 0} tools available`);
    }

    if (message.method === 'initialize') {
      setServerInfo({
        name: message.params.serverInfo?.name || 'MCP Server',
        version: message.params.serverInfo?.version || 'unknown'
      });
    }
  }, []);

  const callTool = useCallback(async (toolName, argumentsObj = {}) => {
    if (!isConnected || !wsRef.current) {
      throw new Error('Not connected to MCP server');
    }

    return new Promise((resolve, reject) => {
      const requestId = Date.now();
      const request = {
        jsonrpc: '2.0',
        id: requestId,
        method: 'tools/call',
        params: {
          name: toolName,
          arguments: JSON.stringify(argumentsObj)
        }
      };

      const timeout = setTimeout(() => {
        reject(new Error(`Tool call timeout: ${toolName}`));
      }, 30000);

      const handleResponse = (message) => {
        if (message.id === requestId) {
          clearTimeout(timeout);
          wsRef.current.removeEventListener('message', handleResponse);

          if (message.error) {
            reject(new Error(message.error.message));
          } else {
            resolve(message.result);
          }
        }
      };

      wsRef.current.addEventListener('message', handleResponse);
      wsRef.current.send(JSON.stringify(request));
    });
  }, [isConnected]);

  // 👇 CRITICAL: Expose MCP client globally for ChatInterface
  useEffect(() => {
    window.mcpClient = {
      callTool,
      tools,
      isConnected,
      serverInfo,
      connectionStatus,
      connect,
      disconnect
    };

    return () => {
      // Cleanup on unmount
      delete window.mcpClient;
    };
  }, [callTool, tools, isConnected, serverInfo, connectionStatus, connect, disconnect]);

  // Request tools list on connect
  useEffect(() => {
    if (isConnected && wsRef.current) {
      const toolsRequest = {
        jsonrpc: '2.0',
        id: Date.now(),
        method: 'tools/list'
      };
      wsRef.current.send(JSON.stringify(toolsRequest));
    }
  }, [isConnected]);

  return {
    isConnected,
    tools,
    serverInfo,
    connectionStatus,
    connect,
    disconnect,
    callTool
  };
};