import { useState, useRef, useEffect, useCallback } from 'react';
import { callAzureChat } from '../services/azureChat'; // New service
import { getResponseFromAzureMock } from '../services/chatMock';
import { ToolCallExecutor } from './ToolCallExecutor';
import { fetchCsrfToken } from '../services/api/fetchCsrfService';
import './ChatInterface.css';

export const ChatInterface = () => {
    const [messages, setMessages] = useState([
        {
            role: 'assistant',
            content: '🚀 Connected! I can help you with 3DX APIs: requirements, parts, simulations, and more. Ask me anything!'
        }
    ]);
    const [input, setInput] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const [isToolRunning, setIsToolRunning] = useState(false);
    const [waitDots, setWaitDots] = useState('.');
    const [toolResult, setToolResult] = useState(null);
    const [csrfToken, setCsrfToken] = useState(null);
    const [securityContext, setSecurityContext] = useState(null);
    const initSessionRef = useRef(false);
    const messagesEndRef = useRef(null);

    const scrollToBottom = useCallback(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, []);

    useEffect(scrollToBottom, [messages, scrollToBottom]);

    const isWaiting = isLoading || isToolRunning;

    useEffect(() => {
        if (!isWaiting) {
            setWaitDots('.');
            return;
        }

        const frames = ['.', '..', '...'];
        let index = 0;
        const timer = setInterval(() => {
            index = (index + 1) % frames.length;
            setWaitDots(frames[index]);
        }, 450);

        return () => clearInterval(timer);
    }, [isWaiting]);

    useEffect(() => {
        if (initSessionRef.current) {
            return;
        }
        initSessionRef.current = true;

        const initializeSession = async () => {
            const preferredSecurityContext =
                window.widget?.getValue?.('Credentials') ||
                window.widget?.getPreference?.('Credentials')?.defaultValue ||
                null;

            setSecurityContext(preferredSecurityContext);

            if (!preferredSecurityContext) {
                console.warn('[ChatInterface] SecurityContext preference "Credentials" is empty.');
            }

            try {
                const token = await fetchCsrfToken(preferredSecurityContext);
                console.log('[ChatInterface] CSRF token fetched:', token);
                setCsrfToken(token || null);
            } catch (err) {
                console.error('[ChatInterface] Failed to fetch CSRF token:', err);
            }
        };

        initializeSession();
    }, []); // Fetch SecurityContext + CSRF only once per widget session

    const addMessage = useCallback((role, content) => {
        setMessages(prev => [...prev, { role, content }]);
    }, []);

    const addToolCallMessage = useCallback((toolName, args) => {
        addMessage('assistant', `🔧 Calling tool: <strong>${toolName}</strong>`);
    }, [addMessage]);

    const handleSendMessage = async (e) => {
        e.preventDefault();
        console.log('form submitted', e);
        if (!input.trim() || isWaiting) return; //avoid sending empty messages or multiple at once

        const userMessage = input.trim();
        addMessage('user', userMessage);
        setInput('');
        setIsLoading(true);

        try {
            // 1. Send to Azure OpenAI Chat API with tool discovery
            const useMockResponse = false; // Set to true to use mock responses for testing
            const chatResponse = useMockResponse
                ? getResponseFromAzureMock(userMessage)
                : await callAzureChat(userMessage, messages);

            console.log('Chat response:', chatResponse);

            if (chatResponse.toolCalls?.length) {
                setIsToolRunning(true);
                // 2. Execute each tool call via MCP
                for (const toolCall of chatResponse.toolCalls) {
                    addToolCallMessage(toolCall.name, toolCall.args);

                    // 3. Call MCP tool (your hook handles this)
                    try {
                        // //const result = await window.mcpClient?.callTool(toolCall.name, toolCall.args);
                        // console.log('[ChatInterface] MCP tool result:', result);
                        // console.log('[ChatInterface] Setting toolResult state with:', result);
                        setToolResult(chatResponse.toolCalls);
                        console.log('[ChatInterface] toolResult state set');
                        addMessage('assistant', `✅ Alright, execution is in progress. I'll update you once it's done.`);
                    } catch (toolError) {
                        console.error('[ChatInterface] Tool error:', toolError);
                        addMessage('assistant', `❌ Tool failed: ${toolError.message}`);
                        setIsToolRunning(false);
                    }
                }
            } else {
                // No tools, just show response
                addMessage('assistant', chatResponse.response);
            }
        } catch (error) {
            console.error('Chat error:', error);
            addMessage('assistant', `💥 Error: ${error.message}`);
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <div className="chat-container">
            <div className="messages-list">
                {messages.map((msg, i) => (
                    <div key={i} className={`message-bubble ${msg.role}`}>
                        <div
                            className="message-content"
                            dangerouslySetInnerHTML={{ __html: msg.content }}
                        />
                    </div>
                ))}
                {toolResult && (
                    <>
                        {console.log('[ChatInterface] Rendering ToolCallExecutor - toolResult:', toolResult)}
                        <div className="message-bubble assistant">
                            <ToolCallExecutor
                                tools={toolResult}
                                onMessage={addMessage}
                                csrf={csrfToken}
                                securityContext={securityContext}
                                onComplete={() => {
                                    setIsToolRunning(false);
                                    setToolResult(null);
                                }}
                            />
                        </div>
                    </>
                )}
                {isWaiting && (
                    <div className="message-bubble assistant loading">
                        <div className="typing-indicator-text">
                            Waiting{waitDots}
                        </div>
                    </div>
                )}
                <div ref={messagesEndRef} />
            </div>

            <form onSubmit={handleSendMessage} className="chat-input-area">
                <input
                    name="input"
                    type="text"
                    value={input}
                    onChange={(e) => setInput(e.target.value)}
                    placeholder="e.g., 'Get requirements for part ABC123' or 'List recent simulations'"
                    disabled={isWaiting}
                    autoFocus
                />
                <button type="submit" disabled={isWaiting || !input.trim()}>
                    {isWaiting ? waitDots : 'Send'}
                </button>
            </form>
        </div>
    );
};