import { useEffect, useState } from 'react';
import { getTenant, callwebService } from '../utils/helpers';

const placeholderPattern = /\{\s*3dspace\s*\}/i;

const resolveBaseUrl = (tenant, baseUrl) => {
    const normalizedTenant = (tenant || '').replace(/\/+$/, '');
    const rawBaseUrl = (baseUrl || '').trim();

    if (!rawBaseUrl) {
        return normalizedTenant;
    }

    let resolvedBaseUrl = rawBaseUrl.replace(placeholderPattern, normalizedTenant);

    if (resolvedBaseUrl === rawBaseUrl) {
        if (/^https?:\/\//i.test(rawBaseUrl)) {
            resolvedBaseUrl = rawBaseUrl;
        } else if (rawBaseUrl.startsWith('/')) {
            resolvedBaseUrl = `${normalizedTenant}${rawBaseUrl}`;
        } else {
            resolvedBaseUrl = `${normalizedTenant}/${rawBaseUrl}`;
        }
    }

    return resolvedBaseUrl.replace(/\/+$/, '');
};

const resolvePathTemplate = (pathTemplate = '', pathParams = {}) => {
    const template = pathTemplate.startsWith('/') ? pathTemplate : `/${pathTemplate}`;

    return template.replace(/\{([^}]+)\}/g, (_, key) => {
        const value = pathParams?.[key];
        return value == null ? `{${key}}` : encodeURIComponent(String(value));
    });
};

const cleanupQueryArtifacts = (value = '') => value
    .replace(/([?&])\{\}(?=&|$)/g, '$1')
    .replace(/([?&])%7B%7D(?=&|$)/gi, '$1')
    .replace(/[?&]$/g, '');

const splitPathAndQuery = (pathWithQuery = '') => {
    const cleaned = cleanupQueryArtifacts(pathWithQuery || '');
    const [pathPart = '', queryPart = ''] = cleaned.split('?');
    return {
        path: pathPart,
        queryParams: new URLSearchParams(queryPart),
    };
};

const resolveQueryString = (queryParams = {}) => {
    const params = new URLSearchParams();

    Object.entries(queryParams || {}).forEach(([key, value]) => {
        if (value !== undefined && value !== null && value !== '') {
            params.set(key, String(value));
        }
    });

    const query = params.toString();
    return query ? `?${query}` : '';
};

const buildEndpointUrl = (tenant, endpoint) => {
    const base = resolveBaseUrl(tenant, endpoint?.baseUrl);
    const rawPath = resolvePathTemplate(endpoint?.pathTemplate || '', endpoint?.pathParams || {});
    const { path, queryParams: inlineQuery } = splitPathAndQuery(rawPath);
    const endpointQuery = new URLSearchParams(resolveQueryString(endpoint?.queryParams || {}).replace(/^\?/, ''));

    endpointQuery.forEach((value, key) => {
        inlineQuery.set(key, value);
    });

    const query = inlineQuery.toString();
    const safePath = cleanupQueryArtifacts(path);
    const safeQuery = cleanupQueryArtifacts(query);
    return safeQuery ? `${base}${safePath}?${safeQuery}` : `${base}${safePath}`;
};

const PRIMARY_KEYS = [
    'name',
    'title',
    'id',
    'physicalid',
    'identifier',
    'displayName',
    'state',
    'nextState',
    'message',
];

const toReadableValue = (value) => {
    if (value === null || value === undefined) {
        return '';
    }
    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
        return String(value).trim();
    }
    return '';
};

const extractFromObject = (source, keys = PRIMARY_KEYS, maxDepth = 4) => {
    if (!source || typeof source !== 'object') {
        return '';
    }

    const visited = new Set();
    const queue = [{ value: source, depth: 0 }];

    while (queue.length) {
        const { value, depth } = queue.shift();
        if (!value || typeof value !== 'object' || visited.has(value) || depth > maxDepth) {
            continue;
        }
        visited.add(value);

        for (const key of keys) {
            const direct = toReadableValue(value[key]);
            if (direct) {
                return direct;
            }
        }

        if (Array.isArray(value)) {
            for (const item of value) {
                queue.push({ value: item, depth: depth + 1 });
            }
        } else {
            for (const child of Object.values(value)) {
                queue.push({ value: child, depth: depth + 1 });
            }
        }
    }

    return '';
};

const extractFieldsFromObject = (source, keys = [], maxDepth = 4) => {
    const result = {};
    if (!source || typeof source !== 'object' || !Array.isArray(keys) || keys.length === 0) {
        return result;
    }

    const keySet = new Set(keys);
    const visited = new Set();
    const queue = [{ value: source, depth: 0 }];

    while (queue.length) {
        const { value, depth } = queue.shift();
        if (!value || typeof value !== 'object' || visited.has(value) || depth > maxDepth) {
            continue;
        }
        visited.add(value);

        for (const [fieldKey, fieldValue] of Object.entries(value)) {
            if (keySet.has(fieldKey) && result[fieldKey] === undefined) {
                const normalizedValue = toReadableValue(fieldValue);
                if (normalizedValue) {
                    result[fieldKey] = normalizedValue;
                }
            }
        }

        if (Array.isArray(value)) {
            for (const item of value) {
                queue.push({ value: item, depth: depth + 1 });
            }
        } else {
            for (const child of Object.values(value)) {
                queue.push({ value: child, depth: depth + 1 });
            }
        }

        if (keys.every((key) => result[key] !== undefined)) {
            break;
        }
    }

    return result;
};

const inferOperation = (method = '', action = '', pathTemplate = '') => {
    const hint = `${method} ${action} ${pathTemplate}`.toLowerCase();
    if (hint.includes('promote')) return 'promote';
    if (hint.includes('demote')) return 'demote';
    if (hint.includes('changestate') || hint.includes('maturity')) return 'lifecycle transition';
    if (method.toUpperCase() === 'POST' && (hint.includes('create') || hint.includes('/new') || hint.includes('/add'))) return 'create';
    if (method.toUpperCase() === 'POST') return 'create/execute';
    if (method.toUpperCase() === 'GET') return 'read';
    if (method.toUpperCase() === 'PUT' || method.toUpperCase() === 'PATCH') return 'update';
    if (method.toUpperCase() === 'DELETE') return 'delete';
    return 'execute';
};

const buildReturnSummary = (responses = [], tools = []) => {
    if (!responses.length) {
        return 'Tools execution completed. No responses returned.';
    }

    const successCount = responses.filter((item) => item.status).length;
    const totalCount = responses.length;
    const details = responses.map((response, index) => {
        const endpoint = tools?.[index]?.args?.endpoint || {};
        const operation = inferOperation(
            response?.method || endpoint?.method,
            response?.action || endpoint?.action,
            endpoint?.pathTemplate || ''
        );
        const createFields = extractFieldsFromObject(response?.output, ['id', 'identifier', 'name', 'title']);
        const idValue = createFields.id || createFields.identifier || '';
        const nameValue = createFields.name || '';
        const titleValue = createFields.title || '';
        const fallbackTarget = extractFromObject(response?.output) || 'N/A';
        const targetDetails = `id=${idValue || 'N/A'} name=${nameValue || 'N/A'} title=${titleValue || 'N/A'}`;
        const statusText = response?.status ? 'OK' : 'FAILED';
        const toolLabel = response?.toolName || `tool-${index + 1}`;
        if (operation === 'create' || operation === 'create/execute') {
            return `${toolLabel}: ${operation} (${statusText}) ${targetDetails} target=${fallbackTarget}`;
        }
        if (operation === 'promote') {
            return `${toolLabel}: ${operation} (${statusText}) ${targetDetails} target=${fallbackTarget}`;
        }
        return `${toolLabel}: ${operation} (${statusText}) ${targetDetails} target=${fallbackTarget}`;
    });

    return `Tools execution completed. Success: ${successCount}/${totalCount}. ${details.join(' | ')}`;
};

export const ToolCallExecutor = ({ tools, onMessage, csrf, securityContext, onComplete }) => {
    const [result, setResult] = useState(null);
    const [returnResponse, setReturnResponse] = useState('');
    useEffect(() => {
        const executeTools = async () => {
            if (!Array.isArray(tools) || tools.length === 0) {
                return;
            }

            try {
                const tenant = await getTenant();
                const responses = [];

                for (const tool of tools) {
                    const endpoint = tool?.args?.endpoint || {};
                    const method = endpoint?.method || 'GET';
                    const body = endpoint?.body;
                    const toolName = tool?.name || 'tool';
                    const url = buildEndpointUrl(tenant, endpoint);

                    const endpointHeaders =
                        endpoint?.headers && typeof endpoint.headers === 'object' && !Array.isArray(endpoint.headers)
                            ? endpoint.headers
                            : {};

                    console.log('[ToolCallExecutor] endpoint headers:', { endpointHeaders });
                    const requestHeaders = {
                        ...endpointHeaders,
                        ...(csrf && typeof csrf === 'object' ? csrf : {}),
                    };

                    if (securityContext) {
                        requestHeaders.SecurityContext = securityContext;
                    }

                    console.log('[ToolCallExecutor] Executing:', { toolName, method, url, requestHeaders, body });

                    const execution = await callwebService(method, url, body, requestHeaders);
                    const status = Boolean(execution?.status);

                    responses.push({
                        toolName,
                        action: endpoint?.action,
                        method,
                        url,
                        status,
                        output: execution?.output,
                        error: execution?.error || null,
                    });

                    const responseFields = extractFieldsFromObject(execution?.output, ['id', 'identifier', 'name', 'title']);
                    const responseId = responseFields.id || responseFields.identifier || 'N/A';
                    const responseName = responseFields.name || 'N/A';
                    const responseTitle = responseFields.title || 'N/A';

                    const message = status
                        ? `✅ ${toolName} executed successfully. id=${responseId} name=${responseName} title=${responseTitle}`
                        : `❌ ${toolName} failed: ${execution?.error || 'Unknown error'}`;
                    onMessage?.('assistant', message);
                }

                setResult({ success: responses.every(item => item.status), responses });
                const summary = buildReturnSummary(responses, tools);
                setReturnResponse(summary);
                onMessage?.('assistant', `✅ ${summary}`);
            } catch (error) {
                console.error('[ToolCallExecutor] Unexpected error:', error);
                setResult({ success: false, error: error.message });
                onMessage?.('assistant', `❌ Error executing tools: ${error.message}`);
            } finally {
                onComplete?.();
            }
        };

        executeTools();
    }, [tools, onMessage, csrf, securityContext]);

    return (
        <div>
            {result && <div>{'✅ ' + returnResponse}</div>}
        </div>
    );
};
