export const Connection = ({ isConnected, onDisconnect, serverInfo}) => {
  return (
      <div className="connection-panel-compact">
        {isConnected ? (
            <div className="connection-info">
              <div className="status-header">
                <span className="status-badge connected">Connected to {serverInfo?.name}</span>
                <button onClick={onDisconnect} className="btn-text-only">Disconnect</button>
              </div>
            </div>
        ) : null}
      </div>
  );
};
