import React, { useState, useEffect } from 'react';
import { useMCPClient } from '../hooks/useMCPClient';
import { FileTree } from './FileTree';
import './Sidebar.css';
export const Sidebar = ({ isOpen, onToggle }) => {
  const { tools, isConnected, callTool } = useMCPClient();
  const [fileTree, setFileTree] = useState([]);
  const [activeTool, setActiveTool] = useState(null);

  useEffect(() => {
    if (isConnected) {
      // Fetch workspace files via MCP
      callTool('list_files', { path: '.', recursive: true })
        .then(files => setFileTree(files || []))
        .catch(() => setFileTree([]));
    }
  }, [isConnected, callTool]);

  const codingTools = tools.filter(t => ['read_file', 'write_file', 'edit_file', 'list_files', 'execute_command'].includes(t.name));

  return (
    <div className={`sidebar ${isOpen ? 'open' : 'closed'}`}>
      <div className="sidebar-header">
        <h2>BLACKBOXAI</h2>
        <button onClick={onToggle} className="toggle-btn">{'<'}</button>
      </div>
      
      <nav className="sidebar-nav">
        <ul>
          <li className={activeTool === 'files' ? 'active' : ''} onClick={() => setActiveTool('files')}>
            📁 Files
          </li>
          <li className={activeTool === 'tools' ? 'active' : ''} onClick={() => setActiveTool('tools')}>
            🔧 Tools ({codingTools.length})
          </li>
          <li>💬 Conversations</li>
          <li>⚙️ Settings</li>
        </ul>
      </nav>

      <div className="sidebar-content">
        {activeTool === 'files' && (
          <FileTree tree={fileTree} onSelectFile={(path) => console.log('Open:', path)} />
        )}
        {activeTool === 'tools' && (
          <div className="tools-list">
            {codingTools.map(tool => (
              <div key={tool.name} className="tool-item" onClick={() => {/* Prompt for args */}}>
                <span>{tool.name}</span>
                <small>{tool.description}</small>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

