import createMock from '../mocks/chat/createRoute.json';
import connectMock from '../mocks/chat/connect.json';
import promoteMock from '../mocks/chat/promoteRoute.json';
import taskMock from '../mocks/chat/createTask.json';

const deepClone = (value) => JSON.parse(JSON.stringify(value));

const extractPromoteId = (message = '') => {
    // Examples handled:
    // - promote 0E1B0A0B...
    // - promote route 0E1B0A0B...
    // - promote item ENG-123
    const match = message.match(/\bpromote(?:\s+(?:route|item|task|object))?\s+([^\s,;]+)/i);
    return match?.[1]?.trim() || '';
};

const applyPromoteIdToMock = (mockPayload, promoteId) => {
    const cloned = deepClone(mockPayload);
    if (!promoteId || !Array.isArray(cloned?.toolCalls)) {
        return cloned;
    }

    cloned.toolCalls = cloned.toolCalls.map((toolCall) => {
        const endpoint = toolCall?.args?.endpoint;
        if (!endpoint) {
            return toolCall;
        }

        // If promote API uses path param PID, inject it.
        if (endpoint.pathParams && typeof endpoint.pathParams === 'object' && Object.prototype.hasOwnProperty.call(endpoint.pathParams, 'PID')) {
            endpoint.pathParams.PID = promoteId;
        }

        // If lifecycle promote/demote API uses body.data[].id, inject it.
        if (!endpoint.body || typeof endpoint.body !== 'object') {
            endpoint.body = {};
        }

        if (Array.isArray(endpoint.body.data) && endpoint.body.data.length > 0) {
            endpoint.body.data[0].id = promoteId;
        } else if (
            String(endpoint.action || '').toLowerCase().includes('changestate') ||
            String(endpoint.pathTemplate || '').toLowerCase().includes('maturity')
        ) {
            endpoint.body.data = [{ id: promoteId, nextState: 'FROZEN' }];
        }

        return toolCall;
    });

    cloned.response = `${cloned.response} Parsed id: ${promoteId}`;
    return cloned;
};

const fallbackMock = {
    response: "Mock: type 'create' or 'connect' to trigger a mocked response.",
    toolCalls: []
};

export function getResponseFromAzureMock(message = '') {
    const normalized = message.toLowerCase();

    // Create keywords: new, make, build, generate, add, define, etc.
    const createKeywords = /\b(create|new|make|build|generate|add|define|build|establish.*item)\b/;
    if (createKeywords.test(normalized)) {
        return createMock;
    }

    // Connect keywords: connect, link, relate, associate, establish, join, etc.
    const connectKeywords = /\b(connect|link|relate|associate|establish.*connection|join|attach|bind)\b/;
    if (connectKeywords.test(normalized)) {
        return connectMock;
    }

    // Promote keywords: promote, elevate, upgrade, advance, boost, enhance, etc.
    const promoteKeywords = /\b(promote|elevate|upgrade|advance|boost|enhance|raise|improve)\b/;
    if (promoteKeywords.test(normalized)) {
        const promoteId = extractPromoteId(message);
        return applyPromoteIdToMock(promoteMock, promoteId);
    }

    // Task keywords: task, todo, action item, assignment, chore, duty, job, etc.
    const taskKeywords = /\b(task|todo|action item|assignment|chore|duty|job|work item)\b/;
    if (taskKeywords.test(normalized)) {
        return taskMock;
    }

    return fallbackMock;
}
