import { useEffect, useState } from 'react';
import { useMCPClient } from '../../hooks/useMCPClient';
import { ChatInterface } from '../../components/ChatInterface';
import { Sidebar } from '../../components/Sidebar';
import { Connection } from '../../components/Connection';
import '../../styles/blackbox.css';
// import '../../pages/API/App.css'; // Styles in blackbox.css

function App() {
    const { isConnected, tools, connect, disconnect, serverInfo } = useMCPClient();
    const [sidebarOpen, setSidebarOpen] = useState(false);
    const [mcpConnected, setMcpConnected] = useState(false);

    // Auto-connect to MCP backend
    useEffect(() => {
        connect("https://x8rhpby3am.eu-central-1.awsapprunner.com");
    }, [connect]);

    useEffect(() => {
        if (isConnected) {
            setMcpConnected(true);
            console.log("[API] MCP connected, tools:", tools.length);
        }
    }, [isConnected, tools]);

    // Log when component mounts
    useEffect(() => {
        console.log("[API] BLACKBOXAI interface ready");
    }, []);

    // Temporarily bypass MCP wait for demo
    const isReady = true; // setMcpConnected(true); or !mcpConnected ? loading : content

    if (!isReady) {
        return (
            <div className="loading-container">
                <div className="spinner"></div>
                <p>Connecting to MCP Server...</p>
            </div>
        );
    }

    return (
        <div className="blackbox-app">
            <Sidebar 
                isOpen={sidebarOpen} 
                onToggle={() => setSidebarOpen(!sidebarOpen)} 
            />
            <div className={`main-content ${sidebarOpen ? 'sidebar-open' : ''}`}>
                <header className="app-header">
                    <div className="header-left">
                        <h1>BLACKBOXAI</h1>
                        <span className="subtitle">AI Coding Assistant with MCP Tools</span>
                    </div>
                    <Connection
                        isConnected={isConnected}
                        onDisconnect={disconnect}
                        serverInfo={serverInfo}
                    />
                </header>
                <main className="app-main">
                    <ChatInterface className="with-sidebar" />
                </main>
            </div>
        </div>
    );
}

export default App;

